using Microsoft.AspNetCore.Http;
using Newtonsoft.Json;

public static class ReportingApiFunction
{
    [FunctionName("ReportingApi")]
    public static IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("AzureSqlConnectionString");

        // Extract query string parameters
        var queryParams = req.Query;

        // Build dynamic SQL query
        string sqlQuery = "SELECT * FROM YourTableName WHERE 1=1";

        if (queryParams.ContainsKey("param1") && !string.IsNullOrEmpty(queryParams["param1"]))
        {
            sqlQuery += $" AND Param1 = '{queryParams["param1"]}'";
        }

        if (queryParams.ContainsKey("param2") && !string.IsNullOrEmpty(queryParams["param2"]))
        {
            sqlQuery += $" AND Param2 = '{queryParams["param2"]}'";
        }

        // Add more parameters as needed

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            SqlCommand command = new SqlCommand(sqlQuery, connection);
            connection.Open();
